#include <iostream>
#include <string>
#include <vector>
#include <fstream>
#include <cstdlib> // For system()

std::string read_file(const std::string& filename) {
    std::ifstream ifs(filename);
    std::string content((std::istreambuf_iterator<char>(ifs)),
                           (std::istreambuf_iterator<char>()));
    ifs.close();
    return content;
}

void run_test_case(const std::string& input, const std::string& expected_output) {
    std::ofstream input_file("temp_input.txt");
    input_file << input;
    input_file.close();

    system("./a.out < temp_input.txt > temp_output.txt 2>&1");

    std::string actual_output = read_file("temp_output.txt");

    std::cout << "--- Test Case ---\n";
    std::cout << "Input:\n" << input;
    std::cout << "Expected Output:\n" << expected_output;
    std::cout << "Actual Output:\n" << actual_output;

    if (actual_output.find(expected_output) != std::string::npos && !expected_output.empty()) {
        std::cout << "Test Passed! (Output contains expected)\n\n";
    } else if (actual_output.empty() && expected_output.empty()) {
        std::cout << "Test Passed! (Both empty)\n\n";
    } else {
        std::cout << "Test Failed!\n\n";
    }

    system("rm -f temp_input.txt temp_output.txt");
}

